// Salary import script — matches Excel data to athletes/coaches by name, updates salary/TC/IBAN
// Run: node import-salaries.js
// Source: /tmp/salary_data.json (generated by Python extraction)

const https = require('https');
const fs = require('fs');

const API_URL = 'https://atletikpro.vercel.app/api/data';
const SALARY_FILE = '/tmp/salary_data.json';

function norm(s) {
  return (s || '').toUpperCase().trim()
    .replace(/İ/g,'I').replace(/Ğ/g,'G').replace(/Ş/g,'S')
    .replace(/Ç/g,'C').replace(/Ö/g,'O').replace(/Ü/g,'U')
    .normalize('NFD').replace(/[̀-ͯ]/g,'');
}

function apiGet() {
  return new Promise((resolve, reject) => {
    https.get(API_URL, res => {
      let data = '';
      res.on('data', d => data += d);
      res.on('end', () => resolve(JSON.parse(data)));
    }).on('error', reject);
  });
}

function apiPost(body) {
  return new Promise((resolve, reject) => {
    const payload = JSON.stringify(body);
    const url = new URL(API_URL);
    const req = https.request({
      hostname: url.hostname,
      path: url.pathname,
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(payload) },
    }, res => {
      let data = '';
      res.on('data', d => data += d);
      res.on('end', () => resolve(JSON.parse(data)));
    });
    req.on('error', reject);
    req.write(payload);
    req.end();
  });
}

async function main() {
  const salary = JSON.parse(fs.readFileSync(SALARY_FILE, 'utf8'));
  console.log(`Загружено из Excel: ${salary.length} записей`);

  console.log('Получаю базу с сервера...');
  const db = await apiGet();
  const athletes = db.athletes || [];
  const coaches  = db.coaches  || [];
  console.log(`На сервере: ${athletes.length} спортсменов, ${coaches.length} тренеров`);

  // Build lookup by normalized full name
  const athIdx = {};
  athletes.forEach(a => { athIdx[norm(a.name || '')] = a; });
  const coaIdx = {};
  coaches.forEach(c => { coaIdx[norm(c.name || '')] = c; });

  let updAth = 0, updCoa = 0, notFound = [];

  for (const s of salary) {
    const fullName = norm(s.adi + ' ' + s.soyadi);
    const rec = athIdx[fullName] || coaIdx[fullName];

    if (athIdx[fullName]) {
      athIdx[fullName].salary = s.maas;
      athIdx[fullName].tc     = s.tc;
      athIdx[fullName].iban   = s.iban;
      updAth++;
    } else if (coaIdx[fullName]) {
      coaIdx[fullName].salary = s.maas;
      coaIdx[fullName].tc     = s.tc;
      coaIdx[fullName].iban   = s.iban;
      updCoa++;
    } else {
      notFound.push(`${s.adi} ${s.soyadi} [${s.sheet}]`);
    }
  }

  console.log(`\nОбновлено спортсменов: ${updAth}`);
  console.log(`Обновлено тренеров:    ${updCoa}`);
  console.log(`Не найдено:            ${notFound.length}`);
  if (notFound.length) {
    console.log('\nНе найдены в базе:');
    notFound.forEach(n => console.log('  ' + n));
  }

  console.log('\nОтправляю на сервер...');
  const result = await apiPost({ ...db, athletes, coaches });
  console.log('Ответ сервера:', result.message || JSON.stringify(result));
  console.log('\nГотово! Данные залиты на сервер.');
}

main().catch(e => { console.error('Ошибка:', e.message); process.exit(1); });
